{"file_path":"/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/PropertyNamingRuleMutableCollectionTest.kt","content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat
import org.junit.jupiter.api.Test

class PropertyNamingRuleMutableCollectionTest {
    private val propertyNamingRuleAssertThat =
        KtLintAssertThat.assertThatRule { PropertyNamingRule() }

    @Test
    fun `Given an object val property with a mutable collection type then do not require screaming snake case`() {
        val code =
            """
            val foo = object : FooBar {
                val someMap: MutableMap<String, String> = mutableMapOf()
            }
            """.trimIndent()

        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an object val property with a mutable collection type in screaming snake case then do emit`() {
        val code =
            """
            val foo = object : FooBar {
                val SOME_MAP: MutableMap<String, String> = mutableMapOf()
            }
            """.trimIndent()

        propertyNamingRuleAssertThat(code)
            .hasLintViolationWithoutAutoCorrect(2, 9, "Property name should start with a lowercase letter and use camel case")
    }

    @Test
    fun `Given a top level val property with a mutable collection initializer then do not require screaming snake case`() {
        val code =
            """
            val someList = mutableListOf(1, 2, 3)
            """.trimIndent()

        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

